    def test_iterates_through_single_page(self):
        """Test that paginator iterates through all records in a single page"""
        # Setup mock records
        record1 = Mock(id='record_1')
        record2 = Mock(id='record_2')
        record3 = Mock(id='record_3')

        # Setup mock service
        service = Mock()
        api_response = Mock(spec=ApiResponse)
        api_response.body = {'meta': {'cursors': {'after': None, 'before': None}}}
        list_response = ListResponse(
            records=[record1, record2, record3],
            api_response=api_response
        )
        service.list.return_value = list_response

        # Create paginator and collect results
        paginator = Paginator(service, {'limit': 50})
        results = list(paginator)

        # Verify
        assert len(results) == 3
        assert results[0] == record1
        assert results[1] == record2
        assert results[2] == record3
        service.list.assert_called_once_with(params={'limit': 50})

